#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_M 20
#define MAX_N 20
#define MAX_G 20
#define MAX_T 15

// Function to calculate the expected number of turns
double calculate_expected_turns(int M, int N, char maze[MAX_M][MAX_N], double P) {
    // Initialize the expected turns for each state
    double expected_turns[MAX_M * MAX_N + MAX_G];
    for (int i = 0; i < MAX_M * MAX_N + MAX_G; i++) {
        expected_turns[i] = 0.0;
    }

    // Calculate the expected turns using dynamic programming
    for (int i = 0; i < MAX_M; i++) {
        for (int j = 0; j < MAX_N; j++) {
            if (maze[i][j] == '*') {
                expected_turns[i * MAX_N + j] = 0.0;
            } else if (maze[i][j] == '@') {
                // Calculate the expected turns for the gate
                double expected_turn = 0.0;
                for (int k = 0; k < MAX_M; k++) {
                    for (int l = 0; l < MAX_N; l++) {
                        if (maze[k][l] == '@' && (k != i || l != j)) {
                            expected_turn += expected_turns[k * MAX_N + l];
                        }
                    }
                }
                expected_turn /= (MAX_M * MAX_N - 1);
                expected_turns[i * MAX_N + j] = expected_turn;
            } else {
                // Calculate the expected turns for the current state
                double expected_turn = 0.0;
                for (int k = 0; k < 4; k++) {
                    int new_i = i, new_j = j;
                    switch (k) {
                        case 0: new_i--; break;
                        case 1: new_i++; break;
                        case 2: new_j--; break;
                        case 3: new_j++; break;
                    }
                    if (new_i >= 0 && new_i < MAX_M && new_j >= 0 && new_j < MAX_N && maze[new_i][new_j] != '#') {
                        expected_turn += expected_turns[new_i * MAX_N + new_j];
                    }
                }
                expected_turn *= (1 - P) / 3;
                expected_turn += expected_turns[i * MAX_N + j] * P;
                expected_turns[i * MAX_N + j] = expected_turn;
            }
        }
    }

    // Find the starting position and return the expected turns
    for (int i = 0; i < MAX_M; i++) {
        for (int j = 0; j < MAX_N; j++) {
            if (maze[i][j] == 'S') {
                return expected_turns[i * MAX_N + j];
            }
        }
    }
    return 0.0;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int M, N;
        scanf("%d %d", &M, &N);
        char maze[MAX_M][MAX_N];
        for (int i = 0; i < M; i++) {
            scanf("%s", maze[i]);
        }
        double P;
        scanf("%lf", &P);
        double expected_turns = calculate_expected_turns(M, N, maze, P);
        printf("%.2f\n", expected_turns);
    }
    return 0;
}

